/**
 * AppleHIG.stories.js — Apple Human Interface Guidelines motion
 *
 * Values sourced exclusively from:
 *   book/research/motion/motion-systems-benchmark.md
 *
 * Apple HIG is spring-first. No duration tokens — "response" (perceived duration).
 * Three presets: .smooth, .snappy, .bouncy
 * Converted via fromAppleSpring() from the spring-resolver.
 */

import { springToLinear, fromAppleSpring } from '../spring-resolver.js';

export default {
  title: 'Benchmark/AppleHIG',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component:
          'Apple HIG — spring-first motion system. ' +
          'Three presets (.smooth, .snappy, .bouncy) defined by response + bounce (dampingFraction). ' +
          'Apple deliberately uses "response" rather than "duration" — a spring is always moving and ' +
          'ready to redirect.',
      },
    },
  },
};

// ---------------------------------------------------------------------------
// Apple spring presets — from benchmark
// Bounce values: .smooth = 0, .snappy ≈ 0.15, .bouncy ≈ 0.3
// Apple formula: dampingFraction = 1 - (4π × bounce / duration)
// We use fromAppleSpring(response, dampingFraction) to convert to physics params
// ---------------------------------------------------------------------------

// Typical response values inferred from Apple docs (response ≈ perceived duration in s)
// .smooth → 0.5s response, bounce 0 (dampingFraction ≈ 1.0)
// .snappy → 0.4s response, bounce 0.15 (dampingFraction ≈ 0.85)
// .bouncy → 0.5s response, bounce 0.3 (dampingFraction ≈ 0.7)

const APPLE_PRESETS = [
  {
    name: '.smooth',
    response: 0.5,
    bounce: 0,
    dampingFraction: 1.0,
    character: 'Universal default, versatile. No overshoot.',
    color: '#0055bb',
  },
  {
    name: '.snappy',
    response: 0.4,
    bounce: 0.15,
    dampingFraction: 0.85,
    character: 'Crisp, refined. Slight overshoot — decisive.',
    color: '#005544',
  },
  {
    name: '.bouncy',
    response: 0.5,
    bounce: 0.3,
    dampingFraction: 0.7,
    character: 'Playful, physical. Visible overshoot — use only when gesture has momentum.',
    color: '#7700cc',
  },
];

// Resolve each preset
const APPLE_RESOLVED = APPLE_PRESETS.map(p => {
  const params = fromAppleSpring(p.response, p.dampingFraction);
  const resolved = springToLinear(params.stiffness, params.damping, params.mass);
  return {
    ...p,
    stiffness: +params.stiffness.toFixed(1),
    damping: +params.damping.toFixed(1),
    dampingRatio: +resolved.dampingRatio.toFixed(3),
    settlementMs: resolved.duration,
    css: resolved.css,
  };
});

