// ---------------------------------------------------------------------------
export const Signature = {
  name: 'Signature — spring-first philosophy',
  render: () => {
    const el = document.createElement('div');

    const presetRows = APPLE_RESOLVED.map((p, i) => `
      <div class="preset-row">
        <div class="preset-label">
          <span style="font-family:monospace;font-weight:700;color:${p.color};font-size:15px;">${p.name}</span>
          <span class="preset-char">${p.character}</span>
        </div>
        <div class="preset-params">
          response: ${p.response}s &nbsp;·&nbsp; bounce: ${p.bounce} &nbsp;·&nbsp;
          ζ = ${p.dampingRatio} &nbsp;·&nbsp; settles ~${p.settlementMs}ms
        </div>
        <div class="preset-stage">
          <div class="preset-box" id="box${i}" style="background:${p.color}"></div>
          <div class="preset-ref" style="border-color:${p.color}55"></div>
        </div>
      </div>
    `).join('');

    el.innerHTML = `
      <style>
        ${baseStyles}
        .play-btn { padding: 9px 24px; background: #1c1c1e; color: #fff; border: none;
          border-radius: 8px; font-size: 14px; font-weight: 600; cursor: pointer;
          font-family: inherit; margin-bottom: 40px; }
        .play-btn:disabled { opacity: 0.5; cursor: default; }
        .preset-row { margin-bottom: 32px; }
        .preset-label { display:flex; align-items:baseline; gap:16px; margin-bottom:4px; }
        .preset-char { font-size:13px; color:#555; }
        .preset-params { font-size:11px; font-family:monospace; color:#888; margin-bottom:8px; }
        .preset-stage { width:340px; height:52px; background:#f0f0f5; border-radius:10px;
          position:relative; overflow:hidden; }
        .preset-box { width:44px; height:44px; border-radius:10px; position:absolute;
          left:4px; top:4px; }
        .preset-ref { position:absolute; right:4px; top:4px; width:44px; height:44px;
          border:2px dashed #ccc; border-radius:10px; }
        .note-box { background:#f5f5f7; border-radius:8px; padding:16px 20px;
          font-size:13px; color:#333; line-height:1.6; margin-top:40px; }
        .momentum-rule { background:#fff9e6; border-left:3px solid #f5a623; padding:12px 16px;
          border-radius:0 6px 6px 0; font-size:13px; color:#333; line-height:1.6; margin-top:16px; }
      </style>
      <div class="page">
        <div class="sys-badge">Apple HIG</div>
        <div class="page-title">Signature — Spring-first philosophy</div>
        <div class="page-desc">
          All three presets animated simultaneously. Each resolves to a CSS linear() approximation.
          Observe the difference in overshoot and settlement — the key perceptual distinction.
        </div>
        <button class="play-btn" id="playAll">Play all simultaneously</button>
        ${presetRows}
        <div class="note-box">
          Apple's system has no cubic-bezier easing tokens and no duration tokens. The entire motion
          vocabulary is expressed through spring physics. This is the most complete departure from
          the CSS model in this benchmark.
        </div>
        <div class="momentum-rule">
          <strong>Bounce rule:</strong> Overshoot is appropriate only when the originating gesture has velocity
          (swipe, drag). A tap has no momentum — using .bouncy on a tap feels wrong because the gesture does not
          physically justify it.
        </div>
      </div>
    `;

    el.querySelector('#playAll').addEventListener('click', function() {
      this.disabled = true;
      let done = 0;
      APPLE_RESOLVED.forEach((p, i) => {
        const box = el.querySelector(`#box${i}`);
        const anim = box.animate(
          [{ transform: 'translateX(0px)' }, { transform: 'translateX(240px)' }],
          { duration: p.settlementMs, easing: p.css, fill: 'forwards' }
        );
        anim.onfinish = () => {
          done++;
          if (done === APPLE_RESOLVED.length) {
            setTimeout(() => {
              APPLE_RESOLVED.forEach((p2, j) => {
                const b = el.querySelector(`#box${j}`);
                b.animate(
                  [{ transform: 'translateX(240px)' }, { transform: 'translateX(0px)' }],
                  { duration: p2.settlementMs, easing: p2.css, fill: 'forwards' }
                );
              });
              this.disabled = false;
            }, 400);
          }
        };
      });
    });

    return el;
  },
};
